import{IMPORT_STAR}from"../constants.js";export const forEachPassThroughReExport=(r,o)=>{for(const[t,e]of r.reExport)if(t!==IMPORT_STAR&&!1===o(t,e))return!1;return!0};export const forEachAliasReExport=(r,o)=>{for(const[t,e]of r.reExportAs)for(const[r,s]of e)if(!1===o(t,r,s))return!1;return!0};export const forEachNamespaceReExport=(r,o)=>{for(const[t,e]of r.reExportNs)if(!1===o(t,e))return!1;return!0};export const getStarReExportSources=r=>r.reExport.get(IMPORT_STAR);export const getPassThroughReExportSources=(r,o)=>r.reExport.get(o);export const getAliasReExportMap=(r,o)=>r.reExportAs.get(o);export const getNamespaceReExportSources=(r,o)=>r.reExportNs.get(o);